mapper.select:
SELECT s.id AS submissionId, s.problem_id AS problemId, s.problem_title AS problemTitle, c.name AS problemCategory, s.status, s.submit_time AS submitTime FROM submission s LEFT JOIN problem p ON s.problem_id = p.id LEFT JOIN problem_category pc ON p.id = pc.problem_id LEFT JOIN category c ON pc.category_id = c.id WHERE s.user_id = #{userId}
AND s.status = #{query.result}
AND s.problem_title LIKE CONCAT('%', #{query.keyword}, '%')
AND c.name IN
#{category}
ORDER BY s.submit_time
DESC
ASC
